document.addEventListener('DOMContentLoaded', () => {
    // --- 0. Preloader ---
    const preloader = document.querySelector('.fixed.inset-0.z-1000');
    if (preloader) {
        const hidePreloader = () => {
            setTimeout(() => {
                preloader.classList.remove('opacity-100', 'visible', 'scale-105');
                preloader.classList.add('opacity-0', 'invisible', 'scale-100');
                setTimeout(() => {
                    preloader.style.display = 'none';
                }, 1000);
            }, 500); // Small delay to let user see it briefly
        };

        if (document.readyState === 'complete') {
            hidePreloader();
        } else {
            window.addEventListener('load', hidePreloader);
        }
    }

    // --- 1. Navbar Scroll Effect ---
    const header = document.querySelector('header');
    window.addEventListener('scroll', () => {
        if (window.scrollY > 50) {
            header.classList.remove('py-6', 'from-black/80', 'to-transparent', 'bg-linear-to-b');
            header.classList.add('py-4', 'bg-[#080808]/95', 'backdrop-blur-md', 'shadow-lg');
        } else {
            header.classList.add('py-6', 'from-black/80', 'to-transparent', 'bg-linear-to-b');
            header.classList.remove('py-4', 'bg-[#080808]/95', 'backdrop-blur-md', 'shadow-lg');
        }
    });

    // --- 2. Mobile Menu Toggle ---
    const menuBtn = document.querySelector('header button');
    const mobileMenu = document.querySelector('.md\\:hidden.absolute');
    let menuOpen = false;

    if (menuBtn && mobileMenu) {
        menuBtn.addEventListener('click', () => {
            menuOpen = !menuOpen;
            if (menuOpen) {
                mobileMenu.classList.remove('opacity-0', '-translate-y-4', 'invisible');
                mobileMenu.classList.add('opacity-100', 'translate-y-0', 'visible');
            } else {
                mobileMenu.classList.add('opacity-0', '-translate-y-4', 'invisible');
                mobileMenu.classList.remove('opacity-100', 'translate-y-0', 'visible');
            }
        });

        // Close menu on link click
        const mobileLinks = mobileMenu.querySelectorAll('a');
        mobileLinks.forEach(link => {
            link.addEventListener('click', () => {
                menuOpen = false;
                mobileMenu.classList.add('opacity-0', '-translate-y-4', 'invisible');
                mobileMenu.classList.remove('opacity-100', 'translate-y-0', 'visible');
            });
        });
    }

    // --- 3. Scroll Reveal Animations ---
    const revealElements = document.querySelectorAll('.reveal-on-scroll');
    
    const revealOptions = {
        threshold: 0.1,
        rootMargin: "0px 0px -50px 0px"
    };

    const revealObserver = new IntersectionObserver((entries, observer) => {
        entries.forEach(entry => {
            if (entry.isIntersecting) {
                entry.target.classList.remove('opacity-0', 'translate-y-12');
                entry.target.classList.add('opacity-100', 'translate-y-0');
                observer.unobserve(entry.target);
            }
        });
    }, revealOptions);

    revealElements.forEach(el => {
        revealObserver.observe(el);
    });

    // --- 4. Lightbox for Gallery ---
    // The lightbox container is the first fixed div with bg-black/95
    const lightboxContainer = document.querySelectorAll('.fixed.inset-0.bg-black\\/95')[0];
    const lightboxCloseBtn = lightboxContainer ? lightboxContainer.querySelector('button') : null;
    let lightboxImg = null;

    const galleryButtons = document.querySelectorAll('#work button.cursor-zoom-in');
    
    galleryButtons.forEach(btn => {
        btn.addEventListener('click', () => {
            const img = btn.querySelector('img');
            if (img && lightboxContainer) {
                // Remove existing img if any
                if (lightboxImg) lightboxImg.remove();
                
                // Create new image for lightbox
                lightboxImg = document.createElement('img');
                lightboxImg.src = img.src;
                lightboxImg.className = "max-w-[90vw] max-h-[85vh] object-contain rounded-sm shadow-2xl transition-transform duration-700 scale-95 opacity-0";
                
                // Insert before the close button
                lightboxContainer.appendChild(lightboxImg);
                
                // Show lightbox
                lightboxContainer.classList.remove('opacity-0', 'invisible', 'pointer-events-none');
                lightboxContainer.classList.add('opacity-100', 'visible', 'pointer-events-auto');
                
                // Animate image in
                setTimeout(() => {
                    lightboxImg.classList.remove('scale-95', 'opacity-0');
                    lightboxImg.classList.add('scale-100', 'opacity-100');
                }, 50);
            }
        });
    });

    const closeLightbox = () => {
        if (lightboxContainer) {
            lightboxContainer.classList.add('opacity-0', 'invisible', 'pointer-events-none');
            lightboxContainer.classList.remove('opacity-100', 'visible', 'pointer-events-auto');
            if (lightboxImg) {
                lightboxImg.classList.add('scale-95', 'opacity-0');
                lightboxImg.classList.remove('scale-100', 'opacity-100');
                setTimeout(() => lightboxImg.remove(), 700);
            }
        }
    };

    if (lightboxCloseBtn) lightboxCloseBtn.addEventListener('click', closeLightbox);
    if (lightboxContainer) {
        lightboxContainer.addEventListener('click', (e) => {
            if (e.target === lightboxContainer) closeLightbox();
        });
    }

    // --- 5. Quote Modal ---
    const modalContainer = document.querySelectorAll('.fixed.inset-0.bg-background\\/95')[0];
    const modalInner = modalContainer ? modalContainer.querySelector('.bg-\\[\\#0a0a0a\\]') : null;
    const modalCloseBtn = modalInner ? modalInner.querySelector('button') : null;
    const quotePackageInput = document.getElementById('quote-package');
    
    // Find all "Request Quote" buttons in the pricing section
    const pricingButtons = document.querySelectorAll('#pricing button');
    
    pricingButtons.forEach(btn => {
        btn.addEventListener('click', (e) => {
            const card = e.target.closest('.bg-\\[\\#0a0a0a\\], .bg-\\[\\#0f0f0f\\]');
            if (card && modalContainer) {
                const title = card.querySelector('h3').innerText;
                if (quotePackageInput) quotePackageInput.value = title;
                
                // Show modal overlay
                modalContainer.classList.remove('opacity-0', 'invisible', 'pointer-events-none');
                modalContainer.classList.add('opacity-100', 'visible', 'pointer-events-auto');
                
                // Animate inner
                if (modalInner) {
                    modalInner.classList.remove('translate-y-12', 'scale-95');
                    modalInner.classList.add('translate-y-0', 'scale-100');
                }
            }
        });
    });

    const closeModal = () => {
        if (modalContainer) {
            modalContainer.classList.add('opacity-0', 'invisible', 'pointer-events-none');
            modalContainer.classList.remove('opacity-100', 'visible', 'pointer-events-auto');
            if (modalInner) {
                modalInner.classList.add('translate-y-12', 'scale-95');
                modalInner.classList.remove('translate-y-0', 'scale-100');
            }
        }
    };

    if (modalCloseBtn) modalCloseBtn.addEventListener('click', closeModal);
    if (modalContainer) {
        modalContainer.addEventListener('click', (e) => {
            if (e.target === modalContainer) closeModal();
        });
    }

// --- 6. Bilingual Support (i18n) ---
    const langToggleBtn = document.getElementById('lang-toggle');
    const langToggleBtnMobile = document.getElementById('lang-toggle-mobile');
    const langToggleBtnHeader = document.getElementById('lang-toggle-header');
    let currentLang = localStorage.getItem('lang') || 'en';

    function setLanguage(lang) {
        currentLang = lang;
        localStorage.setItem('lang', lang);

        if(langToggleBtn) langToggleBtn.innerText = lang === 'en' ? 'TR' : 'EN';
        if(langToggleBtnMobile) langToggleBtnMobile.innerText = lang === 'en' ? 'TR' : 'EN';
        if(langToggleBtnHeader) langToggleBtnHeader.innerText = lang === 'en' ? 'TR' : 'EN';

        document.documentElement.lang = lang;

        const translatableElements = document.querySelectorAll('[data-i18n]');
        translatableElements.forEach(el => {
            const key = el.getAttribute('data-i18n');
            if (translations[lang] && translations[lang][key]) {
                if (el.tagName === 'INPUT' || el.tagName === 'TEXTAREA') {
                    el.placeholder = translations[lang][key];
                } else {
                    el.innerHTML = translations[lang][key];
                }
            }
        });
    }

    // Set initial language
    setLanguage(currentLang);

    if (langToggleBtn) {
        langToggleBtn.addEventListener('click', (e) => {
            e.preventDefault();
            setLanguage(currentLang === 'en' ? 'tr' : 'en');
        });
    }
    
    if (langToggleBtnMobile) {
        langToggleBtnMobile.addEventListener('click', (e) => {
            e.preventDefault();
            setLanguage(currentLang === 'en' ? 'tr' : 'en');
        });
    }

    if (langToggleBtnHeader) {
        langToggleBtnHeader.addEventListener('click', (e) => {
            e.preventDefault();
            setLanguage(currentLang === 'en' ? 'tr' : 'en');
        });
    }

});
